import time
import random
from typing import Generator, Iterator

# Source: simulate an infinite stream of sensor events
def sensor_stream() -> Generator[dict, None, None]:
    sensor_ids = ["sensor_A", "sensor_B", "sensor_C"]
    while True:
        yield {
            "sensor_id": random.choice(sensor_ids),
            "temperature": round(random.uniform(15.0, 95.0), 2),
            "timestamp": time.time()
        }
        time.sleep(0.1)  # 10 events/second

# Transform: filter out readings in normal range
def filter_anomalies(stream: Iterator[dict], threshold: float = 80.0) -> Generator[dict, None, None]:
    for event in stream:
        if event["temperature"] > threshold:
            yield event

# Enrich: add alert level
def add_alert_level(stream: Iterator[dict]) -> Generator[dict, None, None]:
    for event in stream:
        event["alert_level"] = "CRITICAL" if event["temperature"] > 90 else "WARNING"
        yield event

# Sink: write to a log (in production: write to Kafka, DB, etc.)
def write_to_sink(stream: Iterator[dict]) -> None:
    for event in stream:
        print(f"[{event['alert_level']}] {event['sensor_id']}: {event['temperature']}°C")

# Compose the pipeline
raw = sensor_stream()
anomalies = filter_anomalies(raw, threshold=80.0)
enriched = add_alert_level(anomalies)
write_to_sink(enriched)

