async def batching_sink(queue: asyncio.Queue, batch_size: int = 200, flush_interval: float = 1.0):
    batch = []
    last_flush = time.monotonic()

    while True:
        try:
            # Wait up to flush_interval for the next item
            timeout = flush_interval - (time.monotonic() - last_flush)
            event = await asyncio.wait_for(queue.get(), timeout=max(0.001, timeout))
            batch.append(event)
        except asyncio.TimeoutError:
            pass  # flush on time even if batch isn't full

